import React, { useEffect, useState, useRef, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useSignalR } from '../hooks/useSignalR';
import { apiGetMessages, apiGetOnlineUsers } from '../services/api';
import Sidebar from '../components/Sidebar';
import ChatWindow from '../components/ChatWindow';
import styles from './ChatPage.module.css';


export default function ChatPage() {
  const { token, user, logout } = useAuth();
  const navigate = useNavigate();
  const { ready, on, off, invoke } = useSignalR(token);

const [onlineUsers, setOnlineUsers] = useState([]) // now [{ id, name }]  const [currentPeer, setCurrentPeer]   = useState(null);
  const [messages, setMessages]         = useState([]);
  const [typingPeerId, setTypingPeerId] = useState(null);
  const typingTimer = useRef(null);
  const userNames   = useRef({}); // id -> name

  // Redirect if not logged in
  useEffect(() => { if (!token) navigate('/'); }, [token, navigate]);

  // Refresh online users list

const refreshOnline = useCallback(async () => {
  try {
    const [ids, allUsers] = await Promise.all([
      apiGetOnlineUsers(token),
      apiGetAllUsers(token),
    ])
    const onlineIds = ids.map(Number).filter(id => id !== user?.id)
    // Map IDs to user objects with real names
    const usersWithNames = onlineIds.map(id => {
      const found = allUsers.find(u => u.id === id)
      return { id, name: found ? found.name : `User ${id}` }
    })
    setOnlineUsers(usersWithNames)
  } catch {}
}, [token, user])
  // SignalR event handlers
  useEffect(() => {
    if (!ready) return;

    const onReceive = (id, senderId, receiverId, content, sentAt, status) => {
      senderId = Number(senderId);
      setMessages(prev => {
        if (currentPeer && senderId === currentPeer.id) {
          invoke('MarkAsRead', id).catch(() => {});
          return [...prev, { id, senderId, receiverId, content, sentAt, status }];
        }
        return prev;
      });
    };

    const onStatusUpdate = (id, status) => {
      setMessages(prev => prev.map(m => m.id === id ? { ...m, status } : m));
    };

    const onRead = (id) => {
      setMessages(prev => prev.map(m => m.id === id ? { ...m, status: 'Read' } : m));
    };

    const onUserOnline  = () => refreshOnline();
    const onUserOffline = () => refreshOnline();

    const onTyping = (senderId) => {
      senderId = Number(senderId);
      setTypingPeerId(senderId);
      clearTimeout(typingTimer.current);
      typingTimer.current = setTimeout(() => setTypingPeerId(null), 2200);
    };

    on('ReceiveMessage',      onReceive);
    on('MessageStatusUpdated', onStatusUpdate);
    on('MessageRead',         onRead);
    on('UserOnline',          onUserOnline);
    on('UserOffline',         onUserOffline);
    on('UserTyping',          onTyping);

    return () => {
      off('ReceiveMessage',      onReceive);
      off('MessageStatusUpdated', onStatusUpdate);
      off('MessageRead',         onRead);
      off('UserOnline',          onUserOnline);
      off('UserOffline',         onUserOffline);
      off('UserTyping',          onTyping);
    };
  }, [ready, on, off, invoke, currentPeer, refreshOnline]);

  // Open chat with a peer
  const openChat = useCallback(async (peer) => {
    setCurrentPeer(peer);
    userNames.current[peer.id] = peer.name;
    setMessages([]);
    try {
      const hist = await apiGetMessages(user.id, peer.id, token);
      setMessages(hist);
    } catch {}
  }, [user, token]);

  // Send message
  const sendMessage = useCallback(async (text) => {
    if (!currentPeer || !text.trim()) return;
    const optimistic = {
      id: Date.now(),
      senderId: user.id,
      receiverId: currentPeer.id,
      content: text,
      sentAt: new Date().toISOString(),
      status: 'Sent',
    };
    setMessages(prev => [...prev, optimistic]);
    try {
      await invoke('SendPrivateMessage', currentPeer.id, text);
    } catch { console.error('Send failed'); }
  }, [currentPeer, user, invoke]);

  // Typing indicator
  const sendTyping = useCallback(() => {
    if (currentPeer) invoke('Typing', currentPeer.id).catch(() => {});
  }, [currentPeer, invoke]);

  const handleLogout = () => { logout(); navigate('/'); };

  return (
    <div className={styles.shell}>
      <Sidebar
        user={user}
        onlineUsers={onlineUsers}
        currentPeer={currentPeer}
        onSelectPeer={openChat}
        onLogout={handleLogout}
      />
      <ChatWindow
        peer={currentPeer}
        messages={messages}
        myId={user?.id}
        isTyping={typingPeerId === currentPeer?.id}
        onSend={sendMessage}
        onTyping={sendTyping}
      />
    </div>
  );
}
